mapper.select:
SELECT ph.history_id AS historyId, ph.drug_id AS drugId, ph.price_type AS priceType, ph.old_price AS oldPrice, ph.new_price AS newPrice, ph.change_rate AS changeRate, ph.adjust_type AS adjustType, ph.batch_no AS batchNo, ph.effective_date AS effectiveDate, ph.reason, ph.operator, ph.create_time AS createTime, d.drug_name, d.specification FROM price_history ph INNER JOIN drug_info d ON ph.drug_id = d.drug_id WHERE 1=1
AND ph.drug_id = #{drugId}
AND DATE(ph.create_time) >= #{startDate}
AND DATE(ph.create_time) <= #{endDate}
AND ph.price_type = #{priceType}
ORDER BY ph.create_time DESC

